input.command:
TOKEN='REDACTED'
KEYHEX=$(kubectl -n ax-next get secret ax-next-secrets -o jsonpath='{.data.http-cookie-key}' | base64 -d)
echo "key length (chars): ${#KEYHEX}"
node -e '
const crypto=require("crypto");
const token=process.argv[1], keyhex=process.argv[2];
const b64url=b=>Buffer.from(b).toString("base64").replace(/\+/g,"-").replace(/\//g,"_").replace(/=+$/,"");
const sign=(keyBuf)=>{const h=crypto.createHmac("sha256",keyBuf).update(token).digest();return b64url(token)+"."+b64url(h);};
const wireHex=sign(Buffer.from(keyhex,"hex"));
const wireRaw=sign(Buffer.from(keyhex,"utf8"));
console.log("WIRE_HEX="+wireHex);
console.log("WIRE_RAW="+wireRaw);
' "$TOKEN" "$KEYHEX" | tee /tmp/ax-qa-wires.txt
echo "=== test HEX-key cookie ===" 
WH=$(grep WIRE_HEX /tmp/ax-qa-wires.txt | cut -d= -f2-)
curl -s -o /dev/null -w "agents: HTTP %{http_code}\n" --max-time 5 http://localhost:9090/api/chat/agents -H "Cookie: ax_auth_session=$WH"
echo "=== test RAW-key cookie ===" 
WR=$(grep WIRE_RAW /tmp/ax-qa-wires.txt | cut -d= -f2-)
curl -s -o /dev/null -w "agents: HTTP %{http_code}\n" --max-time 5 http://localhost:9090/api/chat/agents -H "Cookie: ax_auth_session=$WR"

