WH=$(cat /tmp/ax-qa-cookie.txt)
echo "=== conversations:get for cnv_6VVzUDWGh5x6Xaho36X-2w — turn/block summary ===" 
curl -s --max-time 10 "http://localhost:9090/api/chat/conversations/cnv_6VVzUDWGh5x6Xaho36X-2w" -H "Cookie: ax_auth_session=$WH" | node -e '
const d=JSON.parse(require("fs").readFileSync(0));
const turns=d.turns||d.messages||[];
console.log("top-level keys:", Object.keys(d).join(","));
console.log("turn count:", turns.length);
turns.forEach((t,i)=>{
  const blocks=t.contentBlocks||t.content||[];
  const kinds=blocks.map(b=>b.type).join(",");
  const txt=(blocks.filter(b=>b.type==="text").map(b=>b.text).join(" ")||"").slice(0,70);
  console.log(`#${i} role=${t.role||t.author} blocks=[${kinds}] text="${txt.replace(/\n/g," ")}"`);
});
const all=JSON.stringify(d);
console.log("contains platypus?", all.includes("platypus"));
console.log("contains attachment ref?", /attachment|ax:\/\/|QA-SWEEP-MARKER/.test(all));
'

