const d=JSON.parse(require("fs").readFileSync(0));
const turns=d.turns||[];
console.log("turn count:",turns.length);
turns.forEach((t,i)=>{const b=t.contentBlocks||[];const txt=(b.filter(x=>x.type==="text").map(x=>x.text).join(" ")||"").slice(0,55).replace(/\n/g," ");console.log(`#${i} ${t.role} [${b.map(x=>x.type).join(",")}] "${txt}"`);});
const s=JSON.stringify(d); console.log("platypus?",s.includes("platypus"),"| cowsay-403-text?",s.includes("security policy"),"| thats-all?",s.includes("that"));
'

