1	import {
2	  PluginError,
3	  type FileChange,
4	  type WorkspaceApplyBundleInput,
5	  type WorkspaceApplyBundleOutput,
6	  type WorkspaceApplyOutput,
7	  type WorkspaceExportBaselineBundleInput,
8	  type WorkspaceExportBaselineBundleOutput,
9	  type WorkspaceVersion,
10	} from '@ax/core';
11	import {
12	  WorkspaceCommitNotifyRequestSchema,
13	  WorkspaceCommitNotifyResponseSchema,
14	} from '@ax/ipc-protocol';
15	import { filterToPolicy } from '../bundler/filter.js';
16	import { prepareScratchRepo } from '../bundler/scratch.js';
17	import { verifyBundleAuthor } from '../bundler/verify.js';
18	import { walkBundleChanges } from '../bundler/walk.js';
19	import {
20	  internalError,
21	  logInternalError,
22	  validationError,
23	} from '../errors.js';
24	import type { ActionHandler } from './types.js';
25	
26	// ---------------------------------------------------------------------------
27	// POST /workspace.commit-notify (Phase 3 — real implementation, Slice 6d)
28	//
29	// HALF-WIRED WINDOW PARTIALLY CLOSES HERE. Closes fully when Slice 7
30	// ships the runner sender (the runner currently still calls with the
31	// legacy commit-notify shape, which now schema-rejects as 400 — by
32	// design; the half-wired window is closed within this PR by S7).
33	//
34	// Pipeline:
35	//   1. Parse + validate request schema (parentVersion, reason,
36	//      bundleBytes).
37	//   2. Empty-bundle short-circuit: turn wrote nothing → accepted: true
38	//      against the existing parentVersion. No apply, no subscribers.
39	//   3. Snapshot the workspace at `parentVersion` via workspace:list +
40	//      workspace:read. This is the baseline state the deterministic
41	//      reconstructor needs.
42	//   4. prepareScratchRepo: rebuild deterministic baseline + load thin
43	//      bundle into a one-shot scratch repo. Returns
44	//      {repoPath, baselineCommit, dispose}.
45	//   5. verifyBundleAuthor: walk every commit in baseline..HEAD and
46	//      check author + committer == ax-runner. Reject loud on drift.
47	//   6. walkBundleChanges: build canonical FileChange[] for the per-turn
48	//      diff. This is what subscribers see.
49	//   7. filter to .ax/** for the pre-apply hook (subscribers only see
50	//      agent-managed memory; user code paths are not policy-checked).
51	//   8. fire workspace:pre-apply with the .ax-filtered changes.
52	//      Subscribers may reject; surface as accepted:false.
53	//   9. APPLY: prefer workspace:apply-bundle if registered (direct path,
54	//      no rehash). Fall back to workspace:apply(FileChange[]) for
55	//      backends that don't implement bundle apply.
56	//  10. fire workspace:applied with the resulting WorkspaceDelta.
57	//  11. Dispose the scratch repo.
58	//
59	// Response shape: same as today — {accepted: true, version, delta:null}
60	// or {accepted: false, reason}. Wire NEVER carries the delta payload
61	// (Invariant I5 — `WorkspaceDelta` carries lazy fetchers that don't
62	// survive JSON, and exposing the content set across the trust boundary
63	// widens the blast radius of a compromised sandbox).
64	//
65	// Error sanitization: bundler failures (verifier rejection, walk
66	// errors, prepareScratchRepo errors) get sanitized to 500. The
67	// underlying git stderr can echo a temp path or filename, neither of
68	// which the sandbox should see in an error envelope. Real diagnostic
69	// goes to the host log via `logInternalError`.
70	// ---------------------------------------------------------------------------
71	
72	export const workspaceCommitNotifyHandler: ActionHandler = async (
73	  rawPayload,
74	  ctx,
75	  bus,
76	) => {
77	  const parsed = WorkspaceCommitNotifyRequestSchema.safeParse(rawPayload);
78	  if (!parsed.success) {
79	    return validationError(`workspace.commit-notify: ${parsed.error.message}`);
80	  }
81	  const { parentVersion, reason, bundleBytes } = parsed.data;
82	
83	  // Empty-bundle short-circuit: the runner observed an empty turn (no
84	  // commits in baseline..HEAD) and shipped the empty wire shape. No
85	  // apply needed; the workspace stays at parentVersion.
86	  if (bundleBytes === '') {
87	    const body = {
88	      accepted: true as const,
89	      // Preserve the parentVersion the runner sent. The runner's local
90	      // baseline ref is still pinned at this version, so subsequent
91	      // turns will line up.
92	      version: (parentVersion ?? '') as WorkspaceVersion,
93	      delta: null,
94	    };
95	    const checked = WorkspaceCommitNotifyResponseSchema.safeParse(body);
96	    if (!checked.success) {
97	      logInternalError(
98	        ctx.logger,
99	        'workspace.commit-notify',
100	        new Error(`response shape drift (empty-bundle): ${checked.error.message}`),
101	      );
102	      return internalError();
103	    }
104	    return { status: 200, body: checked.data };
105	  }
106	
107	  const parent = (parentVersion as WorkspaceVersion | null) ?? null;
108	
109	  // Get the workspace's baseline bundle. The workspace plugin (e.g.,
110	  // workspace-git-server) bundles its mirror cache state at `parent`;
111	  // we load it into our scratch repo so the runner's thin bundle's
112	  // prereq is satisfied by construction.
113	  //
114	  // PHASE 3 BACKEND CONTRACT: any workspace backend participating in
115	  // the bundle wire MUST register `workspace:export-baseline-bundle`.
116	  // Without it, the host can't load the runner's thin bundle on top
117	  // of the prior workspace state — there's no way to reconstruct the
118	  // prior turn's actual commit OID (it had real wall-clock timestamps
119	  // from the runner side).
120	  //
121	  // For the FIRST apply only (parent=null), a deterministic empty-
122	  // baseline reconstruction would work, but we don't take that
123	  // shortcut: it would let a non-Phase-3 backend appear to work for
124	  // turn 1 then break loudly on turn 2 (worst kind of silent
125	  // regression). Reject up front.
126	  if (!bus.hasService('workspace:export-baseline-bundle')) {
127	    logInternalError(
128	      ctx.logger,
129	      'workspace.commit-notify',
130	      new Error(
131	        'no registered workspace plugin implements workspace:export-baseline-bundle (Phase 3 thin-bundle wire requires it; provided by @ax/workspace-git and @ax/workspace-git-server)',
132	      ),
133	    );
134	    return internalError();
135	  }
136	  let baselineBundleBytes: string;
137	  try {
138	    const out = await bus.call<
139	      WorkspaceExportBaselineBundleInput,
140	      WorkspaceExportBaselineBundleOutput
